parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

const lead = {
  name:      body.name      || 'Unknown',
  email:     body.email     || '',
  company:   body.company   || '',
  budget:    body.budget    || '',
  authority: body.authority || '',
  need:      body.need      || '',
  timing:    body.timing    || ''
};

return [{ json: lead }];

